#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new;
my $next = $cgi->param('next');

if (defined $next && $next =~ m/^(https?:\/\/[^\s]+)/) {
    print "Location: $1\n\n";
} else {
    print "Status: 400 Bad Request\n\n";
}